const item = $input.first().json;

// Extraer remitente
let fromString = '';
if (typeof item.from === 'string') fromString = item.from;
else if (item.from?.text) fromString = item.from.text;
else if (item.from?.value?.[0]) {
  const v = item.from.value[0];
  fromString = `${v.name || ''} <${v.address || ''}>`;
} else fromString = JSON.stringify(item.from);

const subject = item.subject || '';

// Usar el contenido HTML del correo para obtener más texto
let htmlContent = item.html || '';
let bodyText = htmlContent
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

if (bodyText.length < 200) {
  bodyText = item.text || '';
}

// =============== MEJORA 1: Aumento de límite de caracteres ===============
const maxChars = 12000; // antes 8000
if (bodyText.length > maxChars) {
  bodyText = bodyText.substring(0, maxChars);
}

bodyText = bodyText.replace(/-{5,}/g, '').replace(/\n{3,}/g, '\n\n');

// =============== MEJORA 2: Prompt mejorado (sin máximo fijo) ===============
const prompt = `Eres un asistente de reclutamiento. Extrae del siguiente correo TODAS las ofertas de trabajo que aparecen listadas en el cuerpo. No omitas ninguna; si hay más de 5, inclúyelas todas en el array de salida. Para cada oferta, devuelve un JSON con esta estructura EXACTA:
{
  "ofertas": [
    {
      "titulo": "",
      "empresa": "",
      "ubicacion": "",
      "sector": "",
      "tamano": "",
      "requisitos_tecnicos": [],
      "anos_experiencia": null,
      "responsabilidades": [],
      "herramientas": [],
      "url_oferta": null,
      "resumen": "",
      "experiencia_requerida": null,
      "modalidad": null,
      "idioma_requerido": null,
      "nivel_idioma": null
    }
  ]
}
- sector: industria de la empresa (ej. "Banca", "Tecnología", etc.). Si no se menciona, pon null.
- tamano: número de empleados (ej. "De 1.001 a 5.000 empleados", "Menos de 100", etc.). Si no se menciona, pon null.
- experiencia_requerida: años de experiencia solicitados (número, ej. 3). Si no se menciona, pon null.
- modalidad: "remoto", "presencial" o "híbrido". Si no se menciona, pon null.
- idioma_requerido: idioma solicitado (ej. "inglés"). Si no se menciona, pon null.
- nivel_idioma: nivel requerido (ej. "básico", "intermedio", "avanzado", "nativo"). Si no se menciona, pon null.
Si no hay ofertas, devuelve {"ofertas": []}. No añadas texto adicional fuera del JSON.

**IMPORTANTE**: Si el correo NO incluye una lista explícita de requisitos técnicos, INFIERE hasta 5 habilidades técnicas probables para el puesto basándote en su título y sector. USA ESTAS HABILIDADES INFERIDAS ÚNICAMENTE para completar el campo 'requisitos_tecnicos' del JSON interno y así mejorar el cálculo de compatibilidad. NO INCLUYAS estas habilidades inferidas en el campo 'resumen' ni en ningún otro lugar que pueda ser interpretado como un requisito oficial de la oferta.

Correo:
De: ${fromString}
Asunto: ${subject}
Cuerpo: ${bodyText}`;

// =============== MEJORA 3: Aumento de tokens de salida ===============
const requestBody = {
  model: "llama-3.3-70b-versatile",
  messages: [
    {
      role: "user",
      content: prompt
    }
  ],
  temperature: 0,
  max_tokens: 8000 // antes 4000
};

return { body: JSON.stringify(requestBody) };

// Obtener la respuesta de Gemini desde el nodo HTTP Request
const response = $input.first().json;

// Extraer el texto de la respuesta (puede venir en diferentes formatos)
let text = '';
try {
  text = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
} catch (e) {
  text = '';
}

// Si no hay texto, intentar con otras estructuras (por si la API cambia)
if (!text && response.choices?.[0]?.message?.content) {
  text = response.choices[0].message.content; // Formato alternativo
}

// Limpiar el texto: eliminar markdown, espacios, etc.
let cleanText = text.trim();

// Si la respuesta viene envuelta en triple backticks json ... ```, extraer solo el JSON
const jsonMatch = cleanText.match(/```json\s*([\s\S]*?)\s*```/);
if (jsonMatch) {
  cleanText = jsonMatch[1];
} else {
  // Si no tiene triple backticks, buscar un objeto JSON directamente
  const objMatch = cleanText.match(/\{[\s\S]*\}/);
  if (objMatch) {
    cleanText = objMatch[0];
  }
}

// Intentar parsear el JSON
let ofertas = { ofertas: [] };
try {
  const parsed = JSON.parse(cleanText);
  // Asegurar que tenga la propiedad "ofertas"
  if (parsed.ofertas && Array.isArray(parsed.ofertas)) {
    ofertas = parsed;
  } else if (Array.isArray(parsed)) {
    // Si devolvió directamente un array
    ofertas = { ofertas: parsed };
  } else if (parsed.titulo) {
    // Si devolvió una sola oferta (no array)
    ofertas = { ofertas: [parsed] };
  }
} catch (e) {
  console.error('Error parsing JSON:', e.message);
  // Si falla, devolver array vacío
  ofertas = { ofertas: [] };
}

// Asegurar que cada oferta tenga todos los campos necesarios (para evitar errores posteriores)
const camposRequeridos = ['titulo', 'empresa', 'ubicacion', 'requisitos_tecnicos', 'anos_experiencia', 'responsabilidades', 'herramientas', 'url_oferta', 'resumen'];
ofertas.ofertas = ofertas.ofertas.map(oferta => {
  const completa = { ...oferta };
  for (const campo of camposRequeridos) {
    if (completa[campo] === undefined) {
      completa[campo] = (campo === 'requisitos_tecnicos' || campo === 'responsabilidades' || campo === 'herramientas') ? [] : null;
    }
  }
  return completa;
});

// Devolver solo el objeto con el array de ofertas
return ofertas;

// Obtener todos los items de entrada (cada uno es { oferta, perfil })
const items = $input.all();
const resultados = [];

// Función para normalizar texto (quita tildes, minúsculas, caracteres especiales)
function normalizar(texto) {
  return texto
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

// Calcular compatibilidad técnica usando el array de habilidades del perfil
function calcularCompatibilidadTecnica(oferta, perfil) {
  const habilidadesPerfil = (perfil.habilidades_tecnicas || []).map(h => normalizar(h));
  const habilidadesBlandasPerfil = (perfil.habilidades_blandas || []).map(h => normalizar(h));
  const requisitosOferta = (oferta.requisitos_tecnicos || [])
    .map(r => normalizar(r))
    .filter(r => r.length > 0);

  if (requisitosOferta.length === 0) {
    return { puntaje: 50, coincidencias: [], faltantes: [] };
  }

  let puntaje = 50;
  const coincidencias = [];
  const faltantes = [];

  for (const req of requisitosOferta) {
    let coincide = false;

    // 1. Coincidencia exacta o como subcadena (con protección anti-falsos positivos)
    if (req.length <= 2) {
      coincide = habilidadesPerfil.some(h => h === req);
    } else {
      coincide = habilidadesPerfil.some(h => h.includes(req) || req.includes(h));
    }

    // 2. Lógica semántica para casos generales
    if (!coincide) {

      // --- REGLA MEJORADA: "data analysis" (inglés) o "análisis de datos" (español) ---
      if ( (req.includes('data') && req.includes('analysis')) || (req.includes('analisis') && req.includes('datos')) ) {
        coincide = habilidadesPerfil.some(h => 
          h.includes('analisis') || h.includes('data') || h.includes('analista') || h.includes('sql') || h.includes('power bi')
        );
      }
      // --- REGLA MEJORADA: "data visualization" (inglés) o "visualizacion" (español) ---
      else if ( (req.includes('data') && req.includes('visualization')) || req.includes('visualizacion') ) {
        coincide = habilidadesPerfil.some(h => 
          h.includes('visualizacion') || h.includes('power bi') || h.includes('matplotlib') || h.includes('seaborn')
        );
      }
      // "lenguajes de programacion" conecta con Python, SQL, JavaScript, etc.
      else if (req.includes('lenguajes') && req.includes('programacion')) {
        coincide = habilidadesPerfil.some(h => h.includes('python') || h.includes('sql') || h.includes('javascript') || h.includes('java') || h.includes('c#') || h.includes('c++') || h.includes('typescript'));
      }
      // "base de datos" o "bases de datos" conecta con SQL, MySQL, Oracle, etc.
      else if ( (req.includes('base') || req.includes('bases')) && req.includes('datos') ) {
        coincide = habilidadesPerfil.some(h => h.includes('sql') || h.includes('mysql') || h.includes('oracle') || h.includes('postgresql') || h.includes('mongodb'));
      }

      // --- NUEVAS REGLAS SEMÁNTICAS (Respaldadas y Éticas) ---

      // 1. "data science" como concepto general
      else if (req.includes('data') && req.includes('science')) {
        coincide = habilidadesPerfil.some(h => 
          h.includes('python') || h.includes('machine learning') || h.includes('sql') || 
          h.includes('pandas') || h.includes('scikit-learn') || h.includes('visualizacion')
        );
      }
      // 2. "estadisticas"
      else if (req.includes('estadistica')) {
        coincide = habilidadesPerfil.some(h => 
          h.includes('estadisticas') || h.includes('monte carlo') || h.includes('analisis financiero') ||
          h.includes('machine learning')
        );
      }
      // 3. "modelos lineales": coincide con regresión, machine learning
      else if (req.includes('modelo') && (req.includes('lineal') || req.includes('lineales'))) {
        coincide = habilidadesPerfil.some(h => 
          h.includes('regresion') || h.includes('machine learning') || h.includes('optimizacion de umbrales')
        );
      }
      // 4. "data analytics"
      else if (req.includes('data') && req.includes('analytics')) {
        coincide = habilidadesPerfil.some(h => 
          h.includes('analisis de datos') || h.includes('visualizacion') || h.includes('sql') || h.includes('power bi')
        );
      }
      // 5. "inteligencia de negocios"
      else if (req.includes('inteligencia') && req.includes('negocios')) {
        coincide = habilidadesPerfil.some(h => 
          h.includes('power bi') || h.includes('visualizacion') || h.includes('sql') || h.includes('analisis')
        );
      }
      // 6. "cloud computing"
      else if (req.includes('cloud')) {
        coincide = habilidadesPerfil.some(h => 
          h.includes('oci') || h.includes('oracle cloud') || h.includes('infrastructure')
        );
      }
      // 7. "inteligencia artificial"
      else if (req.includes('inteligencia') && req.includes('artificial')) {
        coincide = habilidadesPerfil.some(h => 
          h.includes('machine learning') || h.includes('ia generativa') || 
          h.includes('langgraph') || h.includes('rag') || h.includes('prompt engineering')
        );
      }
      // 8. "aprendizaje automatico"
      else if (req.includes('aprendizaje') && req.includes('automatico')) {
        coincide = habilidadesPerfil.some(h => h.includes('machine learning'));
      }
      // 9. "comunicacion efectiva" como subcadena
      else if (req.includes('comunicacion efectiva')) {
        coincide = habilidadesBlandasPerfil.some(h => h.includes('comunicacion efectiva'));
      }
      // 10. "liderazgo" conecta con "Liderazgo de equipos"
      else if (req.includes('liderazgo')) {
        coincide = habilidadesBlandasPerfil.some(h => h.includes('liderazgo'));
      }
      // 11. "investigación y análisis" conecta con "análisis de datos" (NUEVA REGLA ÉTICA)
      else if (req.includes('investigacion') && req.includes('analisis')) {
        coincide = habilidadesPerfil.some(h => h.includes('analisis de datos') || h.includes('analisis'));
      }
      // 12. "desarrollo de estrategias" conecta con "planificación estratégica" (NUEVA REGLA ÉTICA)
      else if (req.includes('desarrollo') && req.includes('estrategias')) {
        coincide = habilidadesBlandasPerfil.some(h => h.includes('planificacion estrategica'));
      }
      // 13. "gestión de proyectos" conecta con la habilidad blanda
      else if (req.includes('gestion') && req.includes('proyectos')) {
        coincide = habilidadesBlandasPerfil.some(h => 
          h.includes('gestion de proyectos') || h.includes('planificacion estrategica')
        );
      }
      // 14. "desarrollo ágil" o "herramientas ágiles" conecta con Metodologías Ágiles
      else if ((req.includes('desarrollo') && req.includes('agil')) || 
               (req.includes('herramientas') && req.includes('agil'))) {
        coincide = habilidadesPerfil.some(h => 
          h.includes('metodologias agiles') || h.includes('scrum') || h.includes('kanban')
        );
      }
      // --- FIN NUEVAS REGLAS ---
    }

    if (coincide) {
      puntaje += 15;
      coincidencias.push(req);
    } else {
      puntaje -= 5;
      faltantes.push(req);
    }
  }

  puntaje = Math.min(100, Math.max(0, puntaje));
  return { puntaje, coincidencias, faltantes };
}

// Calcular score financiero (con la mejora de incluir "finanzas")
function calcularScoreFinanciero(oferta) {
  let score = 0;
  const sector = (oferta.sector || '').toLowerCase();
  const tamano = (oferta.tamano || '').toLowerCase();

  // Incluir "finanzas", "banco" y similares
  if (sector.includes('banca') || sector.includes('financiero') || sector.includes('finanzas') || sector.includes('banco')) {
    score += 30;
  } else if (sector.includes('tecnología') || sector.includes('consultoría') || sector.includes('ti')) {
    score += 20;
  } else if (sector.includes('telecomunicaciones') || sector.includes('datos')) {
    score += 10;
  }

  if (tamano.includes('1001') || tamano.includes('5000') || tamano.includes('10001')) score += 25;
  else if (tamano.includes('201') || tamano.includes('500') || tamano.includes('1000')) score += 15;
  else if (tamano.includes('menos de') || tamano.includes('1 a') || tamano.includes('pequeña')) score += 5;

  const esEstrategica = score >= 25;
  return { scoreFinanciero: score, esEstrategica };
}

// Procesar cada item
for (const item of items) {
  const oferta = item.json.oferta;
  const perfil = item.json.perfil;

  if (!oferta || !perfil) continue;

  // --- MEJORA: Normalizar modalidad y asignar "No disponible" si viene vacío ---
  if (oferta.modalidad) {
    oferta.modalidad = oferta.modalidad
      .toLowerCase()
      .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
      .replace(/^\w/, (c) => c.toUpperCase());
  } else {
    oferta.modalidad = "No disponible";
  }
  // --- FIN MEJORA ---

  const { puntaje, coincidencias, faltantes } = calcularCompatibilidadTecnica(oferta, perfil);
  const { scoreFinanciero, esEstrategica } = calcularScoreFinanciero(oferta);
  const puntajeTotal = Math.min(100, (puntaje * 0.7) + (scoreFinanciero * 0.3));

  // --- MEJORA EXTENDIDA: Reemplazar nulls y vacíos en todos los campos relevantes ---
  const ofertaEnriquecida = {
    ...oferta,
    puntaje: puntaje,
    puntajeTecnico: puntaje,
    scoreFinanciero,
    esEstrategica,
    puntajeTotal,
    coincidencias: coincidencias.length > 0 ? coincidencias : ["Sin coincidencias"],
    faltantes: faltantes.length > 0 ? faltantes : ["Ninguno"],
    requisitos_tecnicos: oferta.requisitos_tecnicos || [],

    // Campos de texto: si son null, undefined o string vacío -> "No especificado"
    experiencia_requerida: oferta.experiencia_requerida || "No especificado",
    modalidad: oferta.modalidad || "No disponible",
    idioma_requerido: oferta.idioma_requerido || "No especificado",
    nivel_idioma: oferta.nivel_idioma || "No especificado",
    tamano: oferta.tamano || "No especificado",
    anos_experiencia: oferta.anos_experiencia || "No especificado",
    url_oferta: oferta.url_oferta || "No especificado",

    // Arrays: si no existen o están vacíos -> ["No especificado"]
    responsabilidades: (oferta.responsabilidades && oferta.responsabilidades.length > 0) ? oferta.responsabilidades : ["No especificado"],
    herramientas: (oferta.herramientas && oferta.herramientas.length > 0) ? oferta.herramientas : ["No especificado"]
  };
  // --- FIN MEJORA EXTENDIDA ---

  resultados.push({
    oferta: ofertaEnriquecida,
    perfil: perfil,
    puntajeTotal: puntajeTotal
  });
}

// Si no hay resultados, devolver array vacío
if (resultados.length === 0) {
  return [];
}

return resultados;

// Obtener todos los items de entrada
const items = $input.all();
if (items.length === 0) return [];

// --- Función para ordenar viñetas por relevancia ---
function ordenarPorRelevancia(viñetas, palabrasClave) {
  return [...viñetas].sort((a, b) => {
    const scoreA = palabrasClave.filter(p => a.toLowerCase().includes(p)).length;
    const scoreB = palabrasClave.filter(p => b.toLowerCase().includes(p)).length;
    return scoreB - scoreA;
  });
}

// --- Ordenar items por puntajeTotal descendente y tomar los 2 primeros ---
const itemsOrdenados = [...items].sort((a, b) => (b.json.puntajeTotal || 0) - (a.json.puntajeTotal || 0));
const topItems = itemsOrdenados.slice(0, 2);

const resultados = [];

// Procesar cada uno de los 2 mejores
for (const inputItem of topItems) {
  const item = inputItem.json;
  const oferta = item.oferta;
  const perfil = item.perfil;

  if (!oferta) continue;

  // Datos de la oferta
  const puntaje = oferta.puntaje ?? oferta.puntajeTecnico ?? 'N/A';
  const coincidencias = oferta.coincidencias || [];
  const faltantes = oferta.faltantes || [];
  const empresa = oferta.empresa || 'la empresa';
  const tituloPuesto = oferta.titulo || 'el puesto';

  const palabrasClaveOferta = coincidencias.map(p => p.toLowerCase());

  // ============================================================
  // PERFIL DE FAUSTO
  // ============================================================
  const nombre = perfil.nombre || "Fausto Enrique Soto Euraque";
  const tituloProfesional = perfil.titulo || "Ingeniero Industrial | Data Scientist | Agentes IA & Machine Learning para Optimización y Rentabilidad | OCI Certified";
  const ubicacion = perfil.ubicacion || "Tegucigalpa, Francisco Morazán, Honduras";
  const email = perfil.email || "fsotoeu@gmail.com";
  const telefono = perfil.telefono || "+504 3231-0875";
  const linkedin = perfil.linkedin || "https://www.linkedin.com/in/fausto-soto";
  const github = perfil.github || "https://github.com/fsoto21/One-alura-data-science";

  let resumen = `Ingeniero Industrial con más de 10 años en optimización de procesos y reducción de costos en el sector energético. Actualmente aplico Ciencia de Datos, Machine Learning y Agentes IA para decisiones estratégicas con ROI medible. Proyecto destacado: sistema de predicción de churn con ROI 8.10x, recall 96.52% y validación Monte Carlo. Certificado en Oracle Cloud (OCI) y Agentes IA (LangGraph, n8n).`;

  if (coincidencias.length > 0) {
    resumen += ` Mi experiencia incluye ${coincidencias.join(', ')}, habilidades alineadas con el puesto de ${tituloPuesto} en ${empresa}.`;
  } else {
    resumen += ` Busco aplicar mis conocimientos en análisis de datos y machine learning al puesto de ${tituloPuesto} en ${empresa}.`;
  }

  // Viñetas de experiencia
  const viñetasFreelance = [
    "Desarrollo de proyectos end-to-end de Ciencia de Datos, Modelado Predictivo e IA orientados a ROI.",
    "Modelo de Predicción de Churn para 7,043 clientes con ROI 8.10x validado con Monte Carlo.",
    "Diseño de pipelines ETL con Pandas/NumPy y más de 10 visualizaciones accionables (Power BI, Matplotlib, Seaborn).",
    "Implementación de flujos de IA Generativa (Gemini) y Prompt Engineering para automatización.",
    "Certificación OCI Foundations Associate y formación avanzada en SQL, Oracle, MySQL, PL/SQL."
  ];

  const viñetasENEE = [
    "Liderazgo técnico en operación, mantenimiento y optimización de red eléctrica nacional.",
    "Coordinación y supervisión de equipo de 12 personas en mediciones y mantenimiento.",
    "Reducción de costos operativos en 20% e incremento de eficiencia operativa en 15% mediante auditorías electro-energéticas.",
    "Garantía de integridad de datos y reportes entre campo y sistemas de información.",
    "Elaboración de planos eléctricos con AutoCAD para actualización de circuitos."
  ];

  const viñetasPROMEF = [
    "Liderazgo en levantamiento y georreferenciación de red eléctrica nacional con GPS.",
    "Consultor del Banco Mundial en proyecto PROMEF: mejora del 20% en eficiencia energética, cumplimiento 100% de hitos.",
    "Transformación de datos de campo en reportes técnicos para decisiones de inversión."
  ];

  const viñetasFreelanceAdaptadas = ordenarPorRelevancia(viñetasFreelance, palabrasClaveOferta);
  const viñetasENEEAdaptadas = ordenarPorRelevancia(viñetasENEE, palabrasClaveOferta);
  const viñetasPROMEFAdaptadas = ordenarPorRelevancia(viñetasPROMEF, palabrasClaveOferta);

  const experiencia = `
**Data Scientist & Business Optimization Consultant (Freelance)** | jul 2023 - actualidad
${viñetasFreelanceAdaptadas.map(v => `- ${v}`).join('\n')}

**Ingeniero de Distribución II (ENEE)** | ene 2015 - jun 2023
${viñetasENEEAdaptadas.map(v => `- ${v}`).join('\n')}

**Coordinador de Levantamiento de Red / Consultor Banco Mundial (PROMEF)** | sept 2011 - dic 2014
${viñetasPROMEFAdaptadas.map(v => `- ${v}`).join('\n')}
`;

  const certificaciones = perfil.certificaciones 
    ? perfil.certificaciones.map(c => `- ${c}`).join('\n')
    : `- Oracle Cloud Infrastructure 2025 Certified Foundations Associate (OCI)
- Inmersión DEV AGENTES DE AI (Alura Latam)
- IA Generativa - ONE
- SQL con MySQL Server de Oracle - ONE
- Programa ONE Tech Foundation G8 - Data Science
- Estadisticas y Machine Learning G8 - ONE
- Programador en Base de Datos con PL/SQL (Módulos 01 y 02)
- Diseño y Programación de Bases de Datos con SQL
- Fundamentos de Bases de Datos`;

  let habilidadesTecnicas = '';
  if (perfil.habilidades_tecnicas) {
    habilidadesTecnicas = perfil.habilidades_tecnicas.join(', ');
  } else {
    habilidadesTecnicas = `Python, Pandas, NumPy, Scikit-learn, CatBoost, SHAP, Machine Learning, Modelado predictivo, clasificación, regresión, optimización de umbrales, SQL, MySQL, Oracle Database, PL/SQL, optimización de consultas, ETL, Matplotlib, Seaborn, Power BI, Oracle Cloud Infrastructure (OCI), LangGraph, RAG, FAISS, Gemini API, n8n, Prompt Engineering, IA Generativa, MLOps, Simulaciones Monte Carlo, PSI, circuit breakers, data drift, Git, GitHub, Linux, AutoCAD, ArcGIS, GPS, georreferenciación, Excel`;
  }

  if (coincidencias.length > 0) {
    habilidadesTecnicas += `\n\n**Habilidades clave para el puesto de ${tituloPuesto} que coinciden con mi perfil:** ${coincidencias.join(', ')}.`;
  }

