  const totalRequisitos = (oferta.requisitos_tecnicos || []).length;
  const totalCoincidencias = (oferta.coincidencias || []).filter(c => c !== "Sin coincidencias").length;
  const totalFaltantes = (oferta.faltantes || []).filter(f => f !== "Ninguno").length;

  let scoreB = scoreA;
  if (totalRequisitos > 0) {
      // Si se cubren todos los faltantes, el número de coincidencias sería totalCoincidencias + totalFaltantes.
